use askama::Template;
use axum::extract::{Path, State};
use axum::http::{HeaderMap, StatusCode};
use axum::response::{Html, IntoResponse, Redirect, Response};
use axum::Form;
use sqlx::PgPool;
use uuid::Uuid;

use super::auth::AuthenticatedUser;
use super::{htmx_response_with_announce, is_htmx_request};
use crate::domain::{InboxItem, InboxItemId};
use crate::services::inbox_service::{
    capture_inbox_item, delete_inbox_item, get_inbox_items, CaptureInboxError, DeleteInboxError,
};

pub struct InboxItemView {
    pub id: String,
    pub title: String,
}

impl From<&InboxItem> for InboxItemView {
    fn from(item: &InboxItem) -> Self {
        Self {
            id: item.id().as_uuid().to_string(),
            title: item.title().as_str().to_string(),
        }
    }
}

#[derive(Template)]
#[template(path = "inbox.html")]
struct InboxTemplate {
    current_page: &'static str,
    inbox_count: i64,
    items: Vec<InboxItemView>,
}

#[derive(Template)]
#[template(path = "inbox_item.html")]
struct InboxItemTemplate {
    item: InboxItemView,
}

pub async fn get_inbox(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
) -> Result<impl IntoResponse, InboxError> {
    let items = get_inbox_items(&pool, &user_id)
        .await
        .map_err(InboxError::Unexpected)?;

    let inbox_count = items.len() as i64;
    let item_views: Vec<InboxItemView> = items.iter().map(InboxItemView::from).collect();

    let template = InboxTemplate {
        current_page: "inbox",
        inbox_count,
        items: item_views,
    };
    Ok(Html(template.render()?))
}

#[derive(serde::Deserialize)]
pub struct CaptureForm {
    pub title: String,
}

pub async fn post_inbox(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Form(form): Form<CaptureForm>,
) -> Result<Response, InboxError> {
    let htmx = is_htmx_request(&headers);

    // Silently ignore empty/whitespace-only submissions
    if form.title.trim().is_empty() {
        if htmx {
            return Ok(StatusCode::NO_CONTENT.into_response());
        }
        return Ok(Redirect::to("/inbox").into_response());
    }

    match capture_inbox_item(&pool, user_id.clone(), form.title).await {
        Ok(item) => {
            if htmx {
                let template = InboxItemTemplate {
                    item: InboxItemView::from(&item),
                };
                let body = template.render().map_err(InboxError::Render)?;
                Ok(htmx_response_with_announce(Html(body), "Captured to inbox"))
            } else {
                Ok(Redirect::to("/inbox").into_response())
            }
        }
        Err(CaptureInboxError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                crate::domain::TodoTitleError::Empty => {
                    if htmx {
                        return Ok(StatusCode::NO_CONTENT.into_response());
                    }
                    return Ok(Redirect::to("/inbox").into_response());
                }
                crate::domain::TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };

            let items = get_inbox_items(&pool, &user_id)
                .await
                .map_err(InboxError::Unexpected)?;
            let inbox_count = items.len() as i64;
            let item_views: Vec<InboxItemView> = items.iter().map(InboxItemView::from).collect();

            let template = InboxTemplate {
                current_page: "inbox",
                inbox_count,
                items: item_views,
            };
            let _ = user_facing; // Title too long error is shown via template if needed
            let body = template.render().map_err(InboxError::Render)?;
            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
        }
        Err(CaptureInboxError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
    }
}

pub async fn post_delete_inbox_item(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(item_id): Path<Uuid>,
) -> Result<Response, InboxError> {
    let htmx = is_htmx_request(&headers);
    let inbox_item_id = InboxItemId::from_uuid(item_id);

    match delete_inbox_item(&pool, &inbox_item_id, &user_id).await {
        Ok(()) => {
            if htmx {
                Ok(htmx_response_with_announce(
                    Html(String::new()),
                    "Inbox item deleted",
                ))
            } else {
                Ok(Redirect::to("/inbox").into_response())
            }
        }
        Err(DeleteInboxError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Inbox item not found</h1>".to_string()),
        )
            .into_response()),
        Err(DeleteInboxError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(DeleteInboxError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
    }
}

#[derive(Debug, thiserror::Error)]
pub enum InboxError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

impl IntoResponse for InboxError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "Inbox error");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

use sqlx::PgPool;

use crate::domain::{InboxItem, InboxItemId, TodoTitle, TodoTitleError, UserId};
use crate::infrastructure::inbox_repository;

#[derive(Debug, thiserror::Error)]
pub enum CaptureInboxError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "capture_inbox_item",
    skip(pool, title),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn capture_inbox_item(
    pool: &PgPool,
    user_id: UserId,
    title: String,
) -> Result<InboxItem, CaptureInboxError> {
    let title = TodoTitle::parse(title)?;
    let item = InboxItem::new(user_id, title);

    inbox_repository::insert_inbox_item(pool, &item)
        .await
        .map_err(|e| {
            CaptureInboxError::Unexpected(anyhow::anyhow!("Failed to insert inbox item: {e}"))
        })?;

    tracing::info!("Inbox item captured");
    Ok(item)
}

#[tracing::instrument(
    name = "get_inbox_items",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn get_inbox_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<InboxItem>, anyhow::Error> {
    let items = inbox_repository::find_inbox_items_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch inbox items: {e}"))?;

    Ok(items)
}

#[tracing::instrument(
    name = "get_inbox_count",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn get_inbox_count(pool: &PgPool, user_id: &UserId) -> Result<i64, anyhow::Error> {
    let count = inbox_repository::count_inbox_items(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count inbox items: {e}"))?;

    Ok(count)
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteInboxError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to delete this inbox item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_inbox_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_inbox_item(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
) -> Result<(), DeleteInboxError> {
    let item = inbox_repository::find_inbox_item_by_id(pool, item_id)
        .await
        .map_err(|e| DeleteInboxError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteInboxError::NotFound)?;

    if item.user_id() != user_id {
        return Err(DeleteInboxError::Unauthorized);
    }

    inbox_repository::delete_inbox_item(pool, item_id)
        .await
        .map_err(|e| {
            DeleteInboxError::Unexpected(anyhow::anyhow!("Failed to delete inbox item: {e}"))
        })?;

    tracing::info!("Inbox item deleted");
    Ok(())
}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{InboxItem, InboxItemId, TodoTitle, UserId};

struct InboxRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
}

impl InboxRecord {
    fn into_domain(self) -> InboxItem {
        let id = InboxItemId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        InboxItem::from_parts(id, user_id, title, self.created_at)
    }
}

pub async fn insert_inbox_item(pool: &PgPool, item: &InboxItem) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO inbox_items (id, user_id, title, created_at)
           VALUES ($1, $2, $3, $4 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        item.created_at() as &DateTime<Utc>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_inbox_items_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<InboxItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        InboxRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM inbox_items WHERE user_id = $1 ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: InboxRecord| r.into_domain())
        .collect())
}

pub async fn count_inbox_items(pool: &PgPool, user_id: &UserId) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM inbox_items WHERE user_id = $1"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn delete_inbox_item(pool: &PgPool, item_id: &InboxItemId) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_inbox_item_by_id(
    pool: &PgPool,
    item_id: &InboxItemId,
) -> Result<Option<InboxItem>, sqlx::Error> {
    let record: Option<InboxRecord> = sqlx::query_as!(
        InboxRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r: InboxRecord| r.into_domain()))
}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{Context, ContextId, ContextName, UserId};

struct ContextRecord {
    id: Uuid,
    user_id: Uuid,
    name: String,
    position: i32,
    created_at: DateTime<Utc>,
}

impl ContextRecord {
    fn into_domain(self) -> Context {
        let id = ContextId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let name = ContextName::parse(self.name).expect("stored context name should be valid");

        Context::from_parts(id, user_id, name, self.position, self.created_at)
    }
}

pub async fn insert_context(pool: &PgPool, context: &Context) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO contexts (id, user_id, name, position, created_at)
           VALUES ($1, $2, $3, $4, $5 :: timestamptz)"#,
        context.id().as_uuid(),
        context.user_id().as_uuid(),
        context.name().as_str(),
        context.position(),
        context.created_at() as &DateTime<Utc>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_contexts_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<Context>, sqlx::Error> {
    let records = sqlx::query_as!(
        ContextRecord,
        r#"SELECT id, user_id, name, position,
           created_at as "created_at: DateTime<Utc>"
           FROM contexts WHERE user_id = $1 ORDER BY position ASC, name ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: ContextRecord| r.into_domain())
        .collect())
}

pub async fn find_context_by_id(
    pool: &PgPool,
    context_id: &ContextId,
) -> Result<Option<Context>, sqlx::Error> {
    let record: Option<ContextRecord> = sqlx::query_as!(
        ContextRecord,
        r#"SELECT id, user_id, name, position,
           created_at as "created_at: DateTime<Utc>"
           FROM contexts WHERE id = $1"#,
        context_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r: ContextRecord| r.into_domain()))
}

pub async fn update_context_name(
    pool: &PgPool,
    context_id: &ContextId,
    name: &ContextName,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE contexts SET name = $1 WHERE id = $2"#,
        name.as_str(),
        context_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn delete_context(pool: &PgPool, context_id: &ContextId) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM contexts WHERE id = $1"#,
        context_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn get_max_position(pool: &PgPool, user_id: &UserId) -> Result<i32, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COALESCE(MAX(position), -1) as "max_pos!" FROM contexts WHERE user_id = $1"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.max_pos)
}

