 83→    State(pool): State<PgPool>,
 84→    headers: HeaderMap,
 85→    Form(form): Form<AddContextForm>,
 86→) -> Result<Response, ContextError> {
 87→    let htmx = is_htmx_request(&headers);
 88→
 89→    if form.name.trim().is_empty() {
 90→        if htmx {
 91→            return Ok(StatusCode::NO_CONTENT.into_response());
 92→        }
 93→        return Ok(Redirect::to("/contexts").into_response());
 94→    }
 95→
 96→    match add_context(&pool, user_id.clone(), form.name).await {
 97→        Ok(context) => {
 98→            if htmx {
 99→                let template = ContextItemTemplate {
100→                    context: ContextView::from(&context),
101→                };
102→                let body = template.render().map_err(ContextError::Render)?;
103→                Ok(htmx_response_with_announce(Html(body), "Context added"))
104→            } else {
105→                Ok(Redirect::to("/contexts").into_response())
106→            }
107→        }
108→        Err(AddContextError::InvalidName(name_err)) => {
109→            let user_facing = match name_err {
110→                ContextNameError::Empty => {
111→                    if htmx {
112→                        return Ok(StatusCode::NO_CONTENT.into_response());
113→                    }
114→                    return Ok(Redirect::to("/contexts").into_response());
115→                }
116→                ContextNameError::TooLong { max, .. } => {
117→                    format!("That name is too long (max {max} characters)")
118→                }
119→            };
120→
121→            render_contexts_with_error(&pool, &user_id, &user_facing).await
122→        }
123→        Err(AddContextError::DuplicateName) => {
124→            render_contexts_with_error(&pool, &user_id, "A context with that name already exists")
125→                .await
126→        }
127→        Err(AddContextError::Unexpected(err)) => Err(ContextError::Unexpected(err)),
128→    }
129→}
