        NextAction::Completed { completed_at, .. } => Some(completed_at),
        NextAction::Active { .. } => None,
    };

    sqlx::query!(
        r#"INSERT INTO next_actions (id, user_id, context_id, title, created_at, completed_at)
           VALUES ($1, $2, $3, $4, $5 :: timestamptz, $6 :: timestamptz)"#,
