                Ok(htmx_response_with_announce(
                    Html(String::new()),
                    "Next action deleted",
                ))
            } else {
                Ok(Redirect::to("/next-actions").into_response())
            }
        }
        Err(DeleteNextActionError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
