  1→use askama::Template;
  2→use axum::extract::{Path, Query, State};
  3→use axum::http::{HeaderMap, StatusCode};
  4→use axum::response::{Html, IntoResponse, Redirect, Response};
  5→use axum::Form;
  6→use sqlx::PgPool;
  7→use uuid::Uuid;
  8→
  9→use super::auth::AuthenticatedUser;
 10→use super::{htmx_response_with_announce, is_htmx_request};
 11→use crate::domain::{Context, ContextId, NextAction, NextActionId, TodoTitleError};
 12→use crate::services::context_service;
 13→use crate::services::inbox_service;
 14→use crate::services::next_action_service::{
 15→    self, AddNextActionError, CompleteNextActionError, DeleteNextActionError,
 16→    UpdateNextActionTitleError,
 17→};
 18→
 19→pub struct NextActionView {
 20→    pub id: String,
 21→    pub title: String,
 22→    pub context_name: String,
 23→}
 24→
 25→pub struct ContextOption {
 26→    pub id: String,
 27→    pub name: String,
 28→}
 29→
 30→#[derive(Template)]
 31→#[template(path = "next_actions.html")]
 32→struct NextActionsTemplate {
 33→    current_page: &'static str,
 34→    inbox_count: i64,
 35→    actions: Vec<NextActionView>,
 36→    contexts: Vec<ContextOption>,
 37→    selected_context: Option<String>,
 38→    error_message: Option<String>,
 39→}
 40→
 41→#[derive(Template)]
 42→#[template(path = "next_action_item.html")]
 43→struct NextActionItemTemplate {
 44→    action: NextActionView,
 45→}
 46→
 47→#[derive(Template)]
 48→#[template(path = "next_action_edit.html")]
 49→struct NextActionEditTemplate {
 50→    action: NextActionView,
 51→}
 52→
 53→fn build_action_view(action: &NextAction, contexts: &[Context]) -> NextActionView {
 54→    let context_name = contexts
 55→        .iter()
 56→        .find(|c| c.id() == action.context_id())
 57→        .map(|c| c.name().as_str().to_string())
 58→        .unwrap_or_else(|| "Unknown".to_string());
 59→
 60→    NextActionView {
 61→        id: action.id().as_uuid().to_string(),
 62→        title: action.title().as_str().to_string(),
 63→        context_name,
 64→    }
 65→}
 66→
 67→#[derive(serde::Deserialize)]
 68→pub struct ContextFilter {
 69→    pub context: Option<Uuid>,
 70→}
 71→
 72→pub async fn get_next_actions(
 73→    AuthenticatedUser(user_id): AuthenticatedUser,
 74→    State(pool): State<PgPool>,
 75→    Query(filter): Query<ContextFilter>,
 76→) -> Result<impl IntoResponse, NextActionError> {
 77→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
 78→        .await
 79→        .map_err(NextActionError::Unexpected)?;
 80→
 81→    let contexts = context_service::list_contexts(&pool, &user_id)
 82→        .await
 83→        .map_err(NextActionError::Unexpected)?;
 84→
 85→    let actions = if let Some(ctx_uuid) = filter.context {
 86→        let ctx_id = ContextId::from_uuid(ctx_uuid);
 87→        next_action_service::list_active_next_actions_by_context(&pool, &user_id, &ctx_id)
 88→            .await
 89→            .map_err(NextActionError::Unexpected)?
 90→    } else {
 91→        next_action_service::list_active_next_actions(&pool, &user_id)
 92→            .await
 93→            .map_err(NextActionError::Unexpected)?
 94→    };
 95→
 96→    let action_views: Vec<NextActionView> = actions
 97→        .iter()
 98→        .map(|a| build_action_view(a, &contexts))
 99→        .collect();
100→
101→    let context_options: Vec<ContextOption> = contexts
102→        .iter()
103→        .map(|c| ContextOption {
104→            id: c.id().as_uuid().to_string(),
105→            name: c.name().as_str().to_string(),
106→        })
107→        .collect();
108→
109→    let selected_context = filter.context.map(|c| c.to_string());
110→
111→    let template = NextActionsTemplate {
112→        current_page: "next_actions",
113→        inbox_count,
114→        actions: action_views,
115→        contexts: context_options,
116→        selected_context,
117→        error_message: None,
118→    };
119→    Ok(Html(template.render()?))
120→}
121→
122→#[derive(serde::Deserialize)]
123→pub struct AddNextActionForm {
124→    pub title: String,
125→    pub context_id: Uuid,
126→}
127→
128→pub async fn post_next_action(
129→    AuthenticatedUser(user_id): AuthenticatedUser,
130→    State(pool): State<PgPool>,
131→    headers: HeaderMap,
132→    Form(form): Form<AddNextActionForm>,
133→) -> Result<Response, NextActionError> {
134→    let htmx = is_htmx_request(&headers);
135→
136→    if form.title.trim().is_empty() {
137→        if htmx {
138→            return Ok(StatusCode::NO_CONTENT.into_response());
139→        }
140→        return Ok(Redirect::to("/next-actions").into_response());
141→    }
142→
143→    let context_id = ContextId::from_uuid(form.context_id);
144→
145→    let contexts = context_service::list_contexts(&pool, &user_id)
146→        .await
147→        .map_err(NextActionError::Unexpected)?;
148→
149→    match next_action_service::add_next_action(&pool, user_id.clone(), context_id, form.title).await
150→    {
151→        Ok(action) => {
152→            if htmx {
153→                let template = NextActionItemTemplate {
154→                    action: build_action_view(&action, &contexts),
155→                };
156→                let body = template.render().map_err(NextActionError::Render)?;
157→                Ok(htmx_response_with_announce(Html(body), "Next action added"))
158→            } else {
159→                Ok(Redirect::to("/next-actions").into_response())
160→            }
161→        }
162→        Err(AddNextActionError::InvalidTitle(title_err)) => {
163→            let user_facing = match title_err {
164→                TodoTitleError::Empty => {
165→                    if htmx {
166→                        return Ok(StatusCode::NO_CONTENT.into_response());
167→                    }
168→                    return Ok(Redirect::to("/next-actions").into_response());
169→                }
170→                TodoTitleError::TooLong { max, .. } => {
171→                    format!("That title is too long (max {max} characters)")
172→                }
173→            };
174→
175→            render_next_actions_with_error(&pool, &user_id, &user_facing).await
176→        }
177→        Err(AddNextActionError::Unexpected(err)) => Err(NextActionError::Unexpected(err)),
178→    }
179→}
180→
181→async fn render_next_actions_with_error(
182→    pool: &PgPool,
183→    user_id: &crate::domain::UserId,
184→    error_message: &str,
185→) -> Result<Response, NextActionError> {
186→    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
187→        .await
188→        .map_err(NextActionError::Unexpected)?;
189→
190→    let contexts = context_service::list_contexts(pool, user_id)
191→        .await
192→        .map_err(NextActionError::Unexpected)?;
193→
194→    let actions = next_action_service::list_active_next_actions(pool, user_id)
195→        .await
196→        .map_err(NextActionError::Unexpected)?;
197→
198→    let action_views: Vec<NextActionView> = actions
199→        .iter()
200→        .map(|a| build_action_view(a, &contexts))
201→        .collect();
202→
203→    let context_options: Vec<ContextOption> = contexts
204→        .iter()
205→        .map(|c| ContextOption {
206→            id: c.id().as_uuid().to_string(),
207→            name: c.name().as_str().to_string(),
208→        })
209→        .collect();
210→
211→    let template = NextActionsTemplate {
212→        current_page: "next_actions",
213→        inbox_count,
214→        actions: action_views,
215→        contexts: context_options,
216→        selected_context: None,
217→        error_message: Some(error_message.to_string()),
218→    };
219→    let body = template.render().map_err(NextActionError::Render)?;
220→    Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
221→}
222→
223→pub async fn post_complete_next_action(
224→    AuthenticatedUser(user_id): AuthenticatedUser,
225→    State(pool): State<PgPool>,
226→    headers: HeaderMap,
227→    Path(action_id): Path<Uuid>,
228→) -> Result<Response, NextActionError> {
229→    let htmx = is_htmx_request(&headers);
230→    let na_id = NextActionId::from_uuid(action_id);
231→
232→    match next_action_service::complete_next_action(&pool, &na_id, &user_id).await {
233→        Ok(()) => {
234→            if htmx {
235→                Ok(htmx_response_with_announce(
236→                    Html(String::new()),
237→                    "Action completed",
238→                ))
239→            } else {
240→                Ok(Redirect::to("/next-actions").into_response())
241→            }
242→        }
243→        Err(CompleteNextActionError::NotFound) => Ok((
244→            StatusCode::NOT_FOUND,
245→            Html("<h1>Next action not found</h1>".to_string()),
246→        )
247→            .into_response()),
248→        Err(CompleteNextActionError::Unauthorized) => Ok((
249→            StatusCode::FORBIDDEN,
250→            Html("<h1>Not authorized</h1>".to_string()),
251→        )
252→            .into_response()),
253→        Err(CompleteNextActionError::Unexpected(err)) => Err(NextActionError::Unexpected(err)),
254→    }
255→}
256→
257→pub async fn post_delete_next_action(
258→    AuthenticatedUser(user_id): AuthenticatedUser,
259→    State(pool): State<PgPool>,
260→    headers: HeaderMap,
261→    Path(action_id): Path<Uuid>,
