284→            Html("<h1>Not authorized</h1>".to_string()),
285→        )
286→            .into_response()),
287→        Err(DeleteNextActionError::Unexpected(err)) => Err(NextActionError::Unexpected(err)),
288→    }
289→}
290→
291→pub async fn get_edit_next_action(
292→    AuthenticatedUser(user_id): AuthenticatedUser,
293→    State(pool): State<PgPool>,
294→    headers: HeaderMap,
295→    Path(action_id): Path<Uuid>,
296→) -> Result<Response, NextActionError> {
297→    let na_id = NextActionId::from_uuid(action_id);
298→    let action =
299→        crate::infrastructure::next_action_repository::find_next_action_by_id(&pool, &na_id)
300→            .await
301→            .map_err(|e| NextActionError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
